(function(){
if(!window.__g)return;
const g=window.__g;
const R=document.getElementById('G25');
if(!R)return;

const css=`*{box-sizing:border-box}.ds{width:64px;height:64px;perspective:180px;cursor:pointer;user-select:none}.dc{width:64px;height:64px;position:relative;transform-style:preserve-3d}.dc.idle{animation:dFl 5s ease-in-out infinite}.dc.spin{animation:dSp .48s linear infinite}@keyframes dFl{0%,100%{transform:rotateX(-15deg) rotateY(25deg)}50%{transform:rotateX(-28deg) rotateY(52deg) rotateZ(6deg)}}@keyframes dSp{from{transform:rotateX(0) rotateY(0)}to{transform:rotateX(720deg) rotateY(1080deg) rotateZ(360deg)}}.df{position:absolute;width:64px;height:64px;background:var(--color-background-primary);border:.5px solid var(--color-border-secondary);border-radius:var(--border-radius-md);display:grid;grid-template:repeat(3,1fr)/repeat(3,1fr);padding:9px;gap:2px}.df1{transform:translateZ(32px)}.df2{transform:rotateY(180deg) translateZ(32px)}.df3{transform:rotateY(90deg) translateZ(32px)}.df4{transform:rotateY(-90deg) translateZ(32px)}.df5{transform:rotateX(90deg) translateZ(32px)}.df6{transform:rotateX(-90deg) translateZ(32px)}.dp{width:7px;height:7px;border-radius:50%;background:var(--color-text-primary);align-self:center;justify-self:center}.dh{visibility:hidden}.g5{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:4px}.cell{border-radius:var(--border-radius-md);display:flex;align-items:center;justify-content:center;font-size:10px;text-align:center;padding:5px 3px;line-height:1.3;aspect-ratio:1;word-break:break-all;transition:transform .12s,border-color .15s,background .15s}.cc{background:var(--color-background-primary);border:.5px solid var(--color-border-primary);color:var(--color-text-primary);font-weight:500}.cr2{background:var(--color-background-secondary);border:.5px solid var(--color-border-secondary);color:var(--color-text-secondary)}.cr3{background:var(--color-background-tertiary);border:.5px solid var(--color-border-tertiary);color:var(--color-text-tertiary)}@keyframes cb{0%,100%{transform:scale(1)}45%{transform:scale(1.18) rotate(-4deg)}}.cbounce{animation:cb .22s ease-out}.csr2,.csr3{border:1px solid var(--color-border-primary)!important;background:var(--color-background-primary)!important;color:var(--color-text-primary)!important;font-weight:500;transform:scale(1.07)}.tag{display:inline-flex;align-items:center;padding:3px 12px;border-radius:20px;font-size:13px;margin:0 2px;background:var(--color-background-secondary);color:var(--color-text-secondary);border:.5px solid var(--color-border-secondary)}.tch{background:var(--color-background-primary);color:var(--color-text-primary);border:.5px solid var(--color-border-primary);font-weight:500}@keyframes dL{to{stroke-dashoffset:0}}@keyframes popD{0%{r:0}65%{r:6}100%{r:4}}`;
const st=document.createElement('style');st.textContent=css;document.head.appendChild(st);

const pip=n=>{const m=[[],[4],[0,8],[0,4,8],[0,2,6,8],[0,2,4,6,8],[0,1,2,6,7,8]];return Array.from({length:9},(_,i)=>`<div class="dp${m[n].includes(i)?'':' dh'}"></div>`).join('')};

R.innerHTML=`<div style="max-width:540px;margin:0 auto;padding:1.75rem 1.25rem;font-family:var(--font-sans)"><div style="display:flex;gap:32px;align-items:flex-start"><div style="flex:0 0 88px;display:flex;flex-direction:column;align-items:center;gap:16px;padding-top:8px"><div class="ds" onclick="window._roll()"><div id="DC" class="dc idle">${[1,2,3,4,5,6].map(n=>`<div class="df df${n}">${pip(n)}</div>`).join('')}</div></div><span id="DH" style="font-size:12px;color:var(--color-text-tertiary);text-align:center;line-height:1.6">点击<br>抽取</span></div><div style="flex:1;min-width:0"><div id="GA" style="position:relative"><div id="GR" class="g5"></div><svg id="SV" style="position:absolute;inset:0;width:100%;height:100%;pointer-events:none;overflow:visible"></svg></div><div style="display:flex;gap:14px;margin-top:12px">${[['var(--color-background-primary)','var(--color-border-primary)','核心'],['var(--color-background-secondary)','var(--color-border-secondary)','行业要素'],['var(--color-background-tertiary)','var(--color-border-tertiary)','场景 / 人群']].map(([b,br,t])=>`<div style="display:flex;align-items:center;gap:6px;font-size:11px;color:var(--color-text-tertiary)"><span style="display:inline-block;width:10px;height:10px;border-radius:3px;background:${b};border:.5px solid ${br}"></span>${t}</div>`).join('')}</div></div></div><div id="RC" style="display:none;background:var(--color-background-secondary);border:.5px solid var(--color-border-tertiary);border-radius:var(--border-radius-lg);padding:1rem 1.25rem;margin-top:1.25rem"><p style="font-size:11px;color:var(--color-text-tertiary);margin-bottom:12px;letter-spacing:.04em">本次选题组合</p><div id="CB" style="margin-bottom:12px;line-height:3"></div><p style="font-size:13px;color:var(--color-text-tertiary);line-height:1.6">三个词组合搜索，找到平台上的真实爆款方向</p></div><div id="BT" style="display:none;gap:8px;margin-top:10px;flex-wrap:wrap"><button onclick="window._roll()" style="flex:1;min-width:80px">再摇一次</button><button onclick="window._search()" style="flex:1;min-width:80px">帮我找选题 ↗</button><button onclick="sendPrompt('换个行业，重新生成 25 宫格选题法')" style="flex:1;min-width:80px">换个行业 ↗</button><button onclick="window._copy()" id="CP" style="flex:1;min-width:80px">复制关键词</button></div></div>`;

const R2I=[6,7,8,11,13,16,17,18],R3I=[0,1,2,3,4,5,9,10,14,15,19,20,21,22,23,24];
let s2=-1,s3=-1,going=false;

function bld(){const gr=document.getElementById('GR');gr.innerHTML='';for(let i=0;i<25;i++){const c=document.createElement('div');c.className='cell';if(i===12){c.classList.add('cc');c.textContent=g.ind;}else if(R2I.includes(i)){c.classList.add('cr2');c.textContent=g.r2[R2I.indexOf(i)];}else{c.classList.add('cr3');c.textContent=g.r3[R3I.indexOf(i)];}gr.appendChild(c);}}bld();

function cls(){return[...document.querySelectorAll('.cell')]}
function gc(i){const cs=cls(),a=document.getElementById('GA'),cr=cs[i].getBoundingClientRect(),ar=a.getBoundingClientRect();return{x:cr.left-ar.left+cr.width/2,y:cr.top-ar.top+cr.height/2}}
function bcp(a,b,o){const mx=(a.x+b.x)/2,my=(a.y+b.y)/2,dx=b.x-a.x,dy=b.y-a.y,l=Math.sqrt(dx*dx+dy*dy)||1;return{x:mx+(-dy/l)*o,y:my+(dx/l)*o}}
function drawL(){const sv=document.getElementById('SV'),ga=document.getElementById('GA');sv.innerHTML='';sv.setAttribute('viewBox',`0 0 ${ga.offsetWidth} ${ga.offsetHeight}`);const c=gc(12),p2=gc(s2),p3=gc(s3),cp1=bcp(c,p2,32),cp2=bcp(p2,p3,-32);[[`M${c.x},${c.y} Q${cp1.x},${cp1.y} ${p2.x},${p2.y}`,0],[`M${p2.x},${p2.y} Q${cp2.x},${cp2.y} ${p3.x},${p3.y}`,.52]].forEach(([d,dl])=>{const p=document.createElementNS('http://www.w3.org/2000/svg','path');p.setAttribute('d',d);p.setAttribute('fill','none');p.setAttribute('stroke','var(--color-text-tertiary)');p.setAttribute('stroke-width','1');p.setAttribute('stroke-linecap','round');p.setAttribute('stroke-dasharray','700');p.setAttribute('stroke-dashoffset','700');p.style.animation=`dL .65s ${dl}s ease-out forwards`;sv.appendChild(p)});[c,p2,p3].forEach((pt,i)=>{const ci=document.createElementNS('http://www.w3.org/2000/svg','circle');ci.setAttribute('cx',pt.x);ci.setAttribute('cy',pt.y);ci.setAttribute('r','4');ci.setAttribute('fill','var(--color-text-secondary)');ci.style.cssText=`transform-origin:${pt.x}px ${pt.y}px;animation:popD .32s ${[0,.44,.96][i]}s ease-out both`;sv.appendChild(ci)})}

window._roll=function(){if(going)return;going=true;s2=-1;s3=-1;document.getElementById('SV').innerHTML='';cls().forEach(c=>c.classList.remove('csr2','csr3'));document.getElementById('RC').style.display='none';document.getElementById('BT').style.display='none';document.getElementById('DC').className='dc spin';document.getElementById('DH').textContent='摇动中';let t=0;const tm=setInterval(()=>{const cs=cls();[...R2I,...R3I].forEach(i=>{if(Math.random()>.42){cs[i].classList.add('cbounce');setTimeout(()=>cs[i].classList.remove('cbounce'),220)}});if(++t>=32){clearInterval(tm);s2=R2I[Math.floor(Math.random()*8)];s3=R3I[Math.floor(Math.random()*16)];document.getElementById('DC').className='dc idle';document.getElementById('DH').textContent='再摇一次';const cs2=cls();cs2[s2].classList.add('csr2');cs2[s3].classList.add('csr3');setTimeout(()=>{drawL();const w2=g.r2[R2I.indexOf(s2)],w3=g.r3[R3I.indexOf(s3)];document.getElementById('CB').innerHTML=`<span class="tag tch">${g.ind}</span><span style="color:var(--color-text-tertiary);font-size:14px;margin:0 4px">+</span><span class="tag">${w2}</span><span style="color:var(--color-text-tertiary);font-size:14px;margin:0 4px">+</span><span class="tag">${w3}</span>`;document.getElementById('RC').style.display='block';document.getElementById('BT').style.display='flex'},90);going=false}},85)};
window._search=function(){if(s2<0||s3<0)return;sendPrompt(`grid25搜索选题：${g.ind} + ${g.r2[R2I.indexOf(s2)]} + ${g.r3[R3I.indexOf(s3)]}`)};
window._copy=function(){if(s2<0||s3<0)return;const w2=g.r2[R2I.indexOf(s2)],w3=g.r3[R3I.indexOf(s3)],btn=document.getElementById('CP');navigator.clipboard.writeText(`${g.ind} + ${w2} + ${w3}`).then(()=>{btn.textContent='已复制';setTimeout(()=>btn.textContent='复制关键词',2000)}).catch(()=>{btn.textContent='复制失败';setTimeout(()=>btn.textContent='复制关键词',2000)})};
})();
